class _AsyncioTaskStatus(abc.TaskStatus):
    def __init__(self, future: asyncio.Future, parent_id: int, spawner: asyncio.Task):
        self._future = future
        self._parent_id = parent_id
        self._spawner = spawner

    def started(self, value: T_contra | None = None) -> None:
        try:
            self._future.set_result(value)
        except asyncio.InvalidStateError:
            if not self._future.cancelled():
                raise RuntimeError(
                    "called 'started' twice on the same task status"
                ) from None

        # Reparent the task to the task group's host task, unless started() was called
        # synchronously by the task that called start(), before the task was spawned
        task = cast(asyncio.Task, current_task())
        if task is not self._spawner:
            _task_states[task].parent_id = self._parent_id

