            )

    if not self._active:
        raise RuntimeError(
            "This task group is not active; no new tasks can be started."
        )

    kwargs = {}
    if task_status_future:
        parent_id = id(current_task())
        kwargs["task_status"] = _AsyncioTaskStatus(
